B.apO=new A.b(B.b,["\u0644\u0627 \u062a\u0644\u0645 \u0646\u0641\u0633\u0643 \u0639\u0646\u062f \u0627\u0644\u0632\u0644\u0644\u060c \u0631\u0627\u0642\u0628 \u0648\u062a\u0639\u0644\u0651\u0645 \u0641\u0642\u0637 \u0641\u064a \u0647\u0630\u0647 \u0627\u0644\u0645\u0631\u062d\u0644\u0629.","No self-blame after a slip; at this stage just observe and learn.","Pas de culpabilit\xe9 apr\xe8s un \xe9cart ; observez et apprenez seulement."],t.w)
